import React, { useState, useEffect } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

// Configuración de la URL de la API (Local o Producción)
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function Categorias() {
  const [categorias, setCategorias] = useState([]);
  const [categoriaActual, setCategoriaActual] = useState({
    id: null,
    nombre: "",
    descripcion: "",
  });

  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  // 📄 CONFIGURACIÓN DE PAGINACIÓN
  const [paginaActual, setPaginaActual] = useState(1);
  const categoriasPorPagina = 6;

  useEffect(() => {
    obtenerCategorias();
  }, []);

  // ✅ OBTENER Y NORMALIZAR DATOS DE POSTGRESQL
  const obtenerCategorias = async () => {
    try {
      setLoading(true);
      const res = await axios.get(`${API_URL}/api/categorias`);

      // Normalizamos los campos para que el frontend no sufra por mayúsculas/minúsculas
      const datosNormalizados = res.data.map((c) => ({
        id: c.id ?? c.CategoriaID,
        nombre: c.nombre ?? c.Nombre,
        descripcion: c.descripcion ?? c.Descripcion,
      }));

      setCategorias(datosNormalizados);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    setCategoriaActual({
      ...categoriaActual,
      [e.target.name]: e.target.value,
    });
  };

  const abrirModalAgregar = () => {
    setCategoriaActual({ id: null, nombre: "", descripcion: "" });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (cat) => {
    setCategoriaActual(cat);
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarCategoria = async (e) => {
    e.preventDefault();
    try {
      if (modoEdicion) {
        await axios.put(`${API_URL}/api/categorias/${categoriaActual.id}`, categoriaActual);
      } else {
        await axios.post(`${API_URL}/api/categorias`, categoriaActual);
      }
      setShowModal(false);
      obtenerCategorias();
    } catch (error) {
      const errorMsg = error.response?.data?.message || "Error al procesar la solicitud";
      alert("❌ " + errorMsg);
    }
  };

  const eliminarCategoria = async (id) => {
    if (!window.confirm("¿Estás seguro de eliminar esta categoría? Si tiene productos asociados, la operación fallará.")) return;
    try {
      await axios.delete(`${API_URL}/api/categorias/${id}`);
      obtenerCategorias();
    } catch (error) {
      const errorMsg = error.response?.data?.message || "No se pudo eliminar";
      alert("⚠️ Error: " + errorMsg);
    }
  };

  // 🔎 LÓGICA DE FILTRADO
  const categoriasFiltradas = categorias.filter((c) =>
    c.nombre.toLowerCase().includes(busqueda.toLowerCase())
  );

  // 📄 CÁLCULO DE PAGINACIÓN
  const totalPaginas = Math.ceil(categoriasFiltradas.length / categoriasPorPagina);
  const inicio = (paginaActual - 1) * categoriasPorPagina;
  const categoriasPaginadas = categoriasFiltradas.slice(inicio, inicio + categoriasPorPagina);

  return (
    <div className="container mt-5">
      <h2 className="mb-4 fw-bold text-primary">📁 Gestión de Categorías</h2>

      {/* BARRA DE HERRAMIENTAS */}
      <div className="d-flex justify-content-between mb-4 gap-3">
        <input
          className="form-control w-50 shadow-sm"
          placeholder="🔍 Buscar categoría por nombre..."
          value={busqueda}
          onChange={(e) => {
            setBusqueda(e.target.value);
            setPaginaActual(1);
          }}
        />

        <button className="btn btn-success shadow-sm d-flex align-items-center" onClick={abrirModalAgregar}>
          <span className="me-2">➕</span> Nueva Categoría
        </button>
      </div>

      {loading ? (
        <div className="text-center mt-5"><div className="spinner-border text-primary"></div></div>
      ) : (
        <>
          {/* GRILLA DE TARJETAS (CARDS) */}
          <div className="row">
            {categoriasPaginadas.map((cat) => (
              <div key={cat.id} className="col-md-4 mb-4">
                <div 
                  className="card shadow-sm h-100 border-0 card-hover" 
                  style={{ cursor: "pointer", transition: "0.3s" }}
                  onClick={() => navigate(`/productos/categoria/${cat.id}`)}
                >
                  <div className="card-body d-flex flex-column justify-content-between">
                    <div>
                      <h5 className="card-title fw-bold text-dark text-center mb-3">{cat.nombre}</h5>
                      <p className="card-text text-muted small text-center">
                        {cat.descripcion || "Sin descripción disponible."}
                      </p>
                    </div>

                    <div className="d-flex justify-content-center gap-2 mt-4">
                      <button
                        className="btn btn-outline-warning btn-sm px-3"
                        onClick={(e) => {
                          e.stopPropagation();
                          abrirModalEditar(cat);
                        }}
                      >
                        ✏️ Editar
                      </button>

                      <button
                        className="btn btn-outline-danger btn-sm px-3"
                        onClick={(e) => {
                          e.stopPropagation();
                          eliminarCategoria(cat.id);
                        }}
                      >
                        🗑️ Eliminar
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* MENSAJE SI NO HAY RESULTADOS */}
          {categoriasFiltradas.length === 0 && (
            <div className="alert alert-light text-center shadow-sm">No se encontraron categorías.</div>
          )}

          {/* 📄 PAGINACIÓN */}
          {totalPaginas > 1 && (
            <nav className="d-flex justify-content-center mt-4">
              <ul className="pagination shadow-sm">
                <li className={`page-item ${paginaActual === 1 ? "disabled" : ""}`}>
                  <button className="page-link" onClick={() => setPaginaActual(paginaActual - 1)}>Anterior</button>
                </li>

                {[...Array(totalPaginas)].map((_, i) => (
                  <li key={i} className={`page-item ${paginaActual === i + 1 ? "active" : ""}`}>
                    <button className="page-link" onClick={() => setPaginaActual(i + 1)}>{i + 1}</button>
                  </li>
                ))}

                <li className={`page-item ${paginaActual === totalPaginas ? "disabled" : ""}`}>
                  <button className="page-link" onClick={() => setPaginaActual(paginaActual + 1)}>Siguiente</button>
                </li>
              </ul>
            </nav>
          )}
        </>
      )}

      {/* MODAL DE REGISTRO / EDICIÓN */}
      {showModal && (
        <div className="modal show d-block" style={{ backgroundColor: "rgba(0,0,0,0.6)" }}>
          <div className="modal-dialog modal-dialog-centered">
            <div className="modal-content border-0 shadow-lg p-4">
              <div className="modal-header border-0">
                <h5 className="modal-title fw-bold">{modoEdicion ? "✏️ Editar" : "✨ Nueva"} Categoría</h5>
                <button type="button" className="btn-close" onClick={() => setShowModal(false)}></button>
              </div>

              <form onSubmit={guardarCategoria}>
                <div className="modal-body">
                  <div className="mb-3">
                    <label className="form-label fw-bold">Nombre</label>
                    <input
                      name="nombre"
                      className="form-control"
                      placeholder="Ej: Electrónica"
                      value={categoriaActual.nombre}
                      onChange={handleChange}
                      required
                    />
                  </div>

                  <div className="mb-3">
                    <label className="form-label fw-bold">Descripción</label>
                    <textarea
                      name="descripcion"
                      className="form-control"
                      placeholder="Detalles de la categoría..."
                      rows="3"
                      value={categoriaActual.descripcion}
                      onChange={handleChange}
                    />
                  </div>
                </div>

                <div className="modal-footer border-0">
                  <button type="button" className="btn btn-light" onClick={() => setShowModal(false)}>Cancelar</button>
                  <button type="submit" className="btn btn-primary px-4">Guardar Categoría</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
